output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
SELECT DISTINCT ?song ?title WHERE {
  ?song p:P118 [ ps:P118 wd:Q5052000 ; pq:P1077 ?position ; pq:P585 ?date ] .
  FILTER(YEAR(?date) = 2020)
  .
  FILTER(xsd:integer(?position) <= 100)
  .
  {
    ?song wdt:P175 ?a1 ; wdt:P175 ?a2 .
    FILTER(?a1 != ?a2)
  } UNION {
    ?song wdt:P1551 ?a1 ; wdt:P1551 ?a2 .
    FILTER(?a1 != ?a2)
  } UNION {
    ?song wdt:P175 ?a1 ; wdt:P1551 ?a2 .
    FILTER(?a1 != ?a2)
  }
  FILTER NOT EXISTS {
    ?song wdt:P175 wd:Q3155215
  }
  FILTER NOT EXISTS {
    ?song wdt:P1551 wd:Q3155215
  }
  OPTIONAL {
    ?song rdfs:label ?title .
    FILTER(lang(?title) = "en")
  }
}

